//! The oath-breach audit — closing the Ulysses lifecycle.
//!
//! An agent SWEARS a crypto-signed oath at spawn (the Ulysses pact, see
//! [`crate::oath`]) and that oath is bound into its grant. This module is the
//! other end: when an agent BREACHES its oath, its lease is revoked (reusing the
//! [`crate::ops::reap`] path) and an append-only breach record is written to the
//! audit log at `$MONSTER_GUARD_HOME/breaches.json`.
//!
//! IMPORTANT — separation of concerns. This is the lease-level enforcement
//! PRIMITIVE only. The *semantic* judgment ("did this agent actually misbehave")
//! belongs to the monster-badchild conduct layer, which calls `oath-breach`
//! (or to `auto::autotick`'s opt-in lease-level reflex, which fires on a coarse
//! conduct signal — sustained inner-vent failure / a recalibration storm). This
//! module just records and enforces; it does not judge.
//!
//! The log is an append-only JSON array, written 0600 (it names which agents
//! breached, who flagged them, and what they swore — the same sensitivity as
//! the fleet ledger). It is created on first append if absent.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;

use serde::{Deserialize, Serialize};

use crate::store;

/// One breach event in the audit trail. Self-describing: who breached, what
/// they swore (carried from the ledger record), why they were flagged, and —
/// crucially — WHO flagged them, so the audit is authenticatable.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub struct BreachRecord {
    /// The breaching subagent's id.
    pub id: String,
    /// Its monster-guard name (`agent-<id>`) — the revoke handle, for audit.
    pub name: String,
    /// The DID that swore the oath (the agent's own DID — Ulysses: the swearer
    /// is the bound). `None` when the agent had sworn no oath. Carried from the
    /// ledger record.
    pub oath_sworn_by: Option<String>,
    /// The STABLE identity that requested this agent's spawn — the UCAN holder
    /// DID (`Subagent.spawned_by`), carried from the ledger record at breach
    /// time. This is the identity trust attaches to: each agent gets a FRESH DID
    /// per spawn (so per-agent trust has no history), but the spawner is stable
    /// across spawns, so its breach history is the basis for [`crate::trust`].
    /// Defaults to `""` for breach logs written before this field existed.
    #[serde(default)]
    pub spawned_by: String,
    /// The oath the agent swore (the signed oath-token path), carried from the
    /// ledger record. `None` when no oath was sworn.
    pub oath: Option<String>,
    /// The caste of the breaching agent.
    pub caste: String,
    /// Human reason for the breach (the conduct judgment that triggered it).
    pub reason: String,
    /// The DID that flagged the breach — the authorizing UCAN's leaf `aud`, so
    /// the audit shows who reported it. For the autotick reflex this is the
    /// autonomic controller's own holder DID.
    pub reported_by: String,
    /// True when a reporter signature was supplied AND verified against the
    /// reporter via [`crate::sign::verify_subagent_signature`]. Lets the audit
    /// distinguish an authenticated report from a merely-authorized one.
    #[serde(default)]
    pub verified: bool,
    /// Unix seconds when the breach was recorded.
    pub ts: u64,
}

fn now_secs() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs())
        .unwrap_or(0)
}

/// The breach audit log path under `$MONSTER_GUARD_HOME`.
pub fn breaches_path() -> PathBuf {
    store::home().join("breaches.json")
}

/// Load the breach audit log. A missing or unreadable/corrupt file reads as an
/// empty audit (the log is append-only; we never lose history to a bad read,
/// but a malformed file should not crash a read either).
pub fn load() -> Vec<BreachRecord> {
    match std::fs::read_to_string(breaches_path()) {
        Ok(s) => serde_json::from_str(&s).unwrap_or_default(),
        Err(_) => Vec::new(),
    }
}

/// Append a breach record to the audit log (creating it 0600 if absent). The
/// log is append-only: we load the existing array, push, and write the whole
/// array back atomically (write-temp + rename) so a torn write never corrupts
/// the audit. The file stays owner-only.
pub fn append(record: BreachRecord) -> Result<(), String> {
    let dir = store::home();
    std::fs::create_dir_all(&dir).map_err(|e| format!("create {}: {e}", dir.display()))?;

    let mut log = load();
    log.push(record);

    let json = serde_json::to_string_pretty(&log).map_err(|e| e.to_string())?;
    let path = breaches_path();
    // Atomic write: a torn audit is worse than no audit. Per-pid temp + rename.
    let tmp = dir.join(format!(".breaches.json.tmp.{}", std::process::id()));
    std::fs::write(&tmp, &json).map_err(|e| e.to_string())?;
    let _ = std::fs::set_permissions(&tmp, std::fs::Permissions::from_mode(0o600));
    std::fs::rename(&tmp, &path).map_err(|e| {
        let _ = std::fs::remove_file(&tmp);
        e.to_string()
    })?;
    Ok(())
}

/// Stamp a breach record at the current time.
#[allow(clippy::too_many_arguments)]
pub fn new_breach(
    id: String,
    name: String,
    oath_sworn_by: Option<String>,
    oath: Option<String>,
    caste: String,
    reason: String,
    reported_by: String,
    verified: bool,
    spawned_by: String,
) -> BreachRecord {
    BreachRecord {
        id,
        name,
        oath_sworn_by,
        oath,
        caste,
        reason,
        reported_by,
        verified,
        spawned_by,
        ts: now_secs(),
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::store::ENV_GUARD;

    #[test]
    fn append_is_append_only_and_round_trips() {
        let _env = ENV_GUARD.lock().unwrap();
        let dir =
            std::env::temp_dir().join(format!("monster-swarm-breachstore-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &dir);

        // No file yet → empty audit.
        assert!(load().is_empty(), "missing audit reads empty");

        // First append creates the 0600 file.
        append(new_breach(
            "a".into(),
            "agent-a".into(),
            Some("did:key:zA".into()),
            Some("oath-tokens/a.oath.ucan".into()),
            "scout".into(),
            "conduct: exfiltration".into(),
            "did:key:zReporter".into(),
            false,
            "did:key:zSpawner".into(),
        ))
        .expect("first append");

        let mode = std::fs::metadata(breaches_path()).unwrap().permissions().mode() & 0o777;
        assert_eq!(mode, 0o600, "breach audit must be owner-only (0600)");

        // Second append is additive — the first record survives (append-only).
        append(new_breach(
            "b".into(),
            "agent-b".into(),
            None,
            None,
            "breeder".into(),
            "conduct: consciousness>=5".into(),
            "did:key:zReporter2".into(),
            true,
            "did:key:zSpawner".into(),
        ))
        .expect("second append");

        let log = load();
        assert_eq!(log.len(), 2, "append-only: both records present");
        assert_eq!(log[0].id, "a");
        assert_eq!(log[0].oath_sworn_by.as_deref(), Some("did:key:zA"));
        assert_eq!(log[0].reported_by, "did:key:zReporter");
        assert!(!log[0].verified);
        assert_eq!(log[0].spawned_by, "did:key:zSpawner", "spawned_by round-trips");
        assert_eq!(log[1].id, "b");
        assert!(log[1].oath.is_none());
        assert!(log[1].verified, "the verified flag round-trips");
        assert_eq!(log[1].spawned_by, "did:key:zSpawner");

        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
    }

    #[test]
    fn spawned_by_defaults_for_old_logs() {
        // A breach log written before `spawned_by` existed must still deserialize
        // (serde default = ""). The trust layer treats an empty spawner as
        // unattributable history.
        let old = r#"[
            {
                "id": "legacy",
                "name": "agent-legacy",
                "oath_sworn_by": null,
                "oath": null,
                "caste": "scout",
                "reason": "conduct: pre-trust breach",
                "reported_by": "did:key:zReporter",
                "ts": 1234567890
            }
        ]"#;
        let log: Vec<BreachRecord> = serde_json::from_str(old).expect("old log deserializes");
        assert_eq!(log.len(), 1);
        assert_eq!(log[0].id, "legacy");
        assert_eq!(log[0].spawned_by, "", "spawned_by defaults to empty for old logs");
        assert!(!log[0].verified, "verified defaults to false for old logs");
    }
}
